-- Refresh planner statistics for one table
ANALYZE orders;

-- Inspect estimated distinct values / correlation
SELECT attname, n_distinct, correlation
FROM pg_stats
WHERE tablename = 'orders';

-- Raise the statistics target (more histogram buckets) for a
-- skewed column, then re-analyze.
ALTER TABLE orders ALTER COLUMN status SET STATISTICS 500;
ANALYZE orders;

EXPLAIN (ANALYZE, BUFFERS)
SELECT * FROM orders
WHERE customer_id = 42 AND status = 'PAID';

-- NON-SARGABLE: function on the indexed column. Index on email
-- is skipped; planner falls back to a sequential scan.
SELECT * FROM users WHERE lower(email) = 'ada@x.io';

-- NON-SARGABLE: arithmetic / casting on the column
SELECT * FROM orders WHERE created_at::date = '2026-06-30';
SELECT * FROM orders WHERE total_amount * 1.1 > 100;

-- SARGABLE rewrites: move the transform to the constant side,
-- or use a range so the raw column is compared directly.
SELECT * FROM orders
WHERE created_at >= '2026-06-30' AND created_at < '2026-07-01';

SELECT * FROM orders WHERE total_amount > 100 / 1.1;

-- Hash index: equality-only lookups
CREATE INDEX idx_sessions_token ON sessions USING hash (token);

-- GIN for full-text search over a generated tsvector
ALTER TABLE articles
  ADD COLUMN body_tsv tsvector
  GENERATED ALWAYS AS (to_tsvector('english', body)) STORED;
CREATE INDEX idx_articles_fts ON articles USING gin (body_tsv);
SELECT id, title FROM articles
WHERE body_tsv @@ websearch_to_tsquery('english', 'query planner');

-- GIN over JSONB for containment queries
CREATE INDEX idx_events_payload ON events USING gin (payload jsonb_path_ops);
SELECT * FROM events WHERE payload @> '{"type":"login"}';

-- BRIN on a time-ordered append-only table: tiny and fast for ranges
CREATE INDEX idx_logs_ts_brin ON logs USING brin (created_at);

-- Partial index: only the rows we actually query for hot paths
CREATE INDEX idx_jobs_pending
  ON jobs (created_at)
  WHERE status = 'PENDING';

-- Enforce a conditional uniqueness rule (one active row per user)
CREATE UNIQUE INDEX uq_one_active_subscription
  ON subscriptions (user_id)
  WHERE active;

-- Expression / functional index: index a computed value
CREATE INDEX idx_users_lower_email ON users (lower(email));
CREATE INDEX idx_orders_year
  ON orders (date_trunc('year', created_at));

// N+1 in an ORM (pseudocode):
const orders = await Order.findAll({ limit: 100 });   // 1 query
for (const o of orders) {
  o.customer = await Customer.findByPk(o.customerId);  // +100 queries
}
// Total: 101 round trips for 100 rows.
